    button.warn {
      background: #8a4f10;
    }

    .aside-scroll {
      padding: 14px;
      overflow: auto;
      display: flex;
      flex-direction: column;
      gap: 14px;
      min-height: 0;
    }

    .card {
      background: rgba(255,255,255,0.62);
