      letter-spacing: 0.04em;
      text-transform: uppercase;
    }

    .sidebar, .aside {
      display: flex;
      flex-direction: column;
      min-height: 0;
    }

    .session-list {
      padding: 12px;
      overflow: auto;
      display: flex;
      flex-direction: column;
      gap: 10px;
    }

    .session-card {
      padding: 12px;
      border-radius: 16px;
      border: 1px solid transparent;
      background: rgba(255,255,255,0.5);
      cursor: pointer;
      transition: transform 120ms ease, border-color 120ms ease, background 120ms ease;
    }

    .session-card:hover { transform: translateY(-1px); border-color: var(--line); }
    .session-card.active { background: var(--accent-soft); border-color: rgba(31, 107, 82, 0.35); }
    .session-title { font-weight: 700; margin-bottom: 6px; }
    .session-meta { color: var(--muted); font-size: 12px; line-height: 1.5; }

    .main {
      display: grid;
      grid-template-rows: auto 1fr auto;
      min-height: 0;
    }

    .chat-meta {
      padding: 14px 18px;
      border-bottom: 1px solid var(--line);
      background: rgba(255,255,255,0.4);
      font-size: 13px;
      color: var(--muted);
    }

    .messages {
      padding: 18px;
      overflow: auto;
      display: flex;
      flex-direction: column;
      gap: 14px;
      min-height: 0;
    }

    .message {
      max-width: 88%;
      padding: 14px 16px;
      border-radius: 18px;
      line-height: 1.6;
      white-space: pre-wrap;
      word-break: break-word;
      background: var(--panel-strong);
      border: 1px solid var(--line);
    }

    .message.user {
      margin-left: auto;
      background: linear-gradient(135deg, #1f6b52, #2c7f62);
      color: white;
      border-color: transparent;
    }

    .message.assistant {
      margin-right: auto;
    }

    .message.loading {
      position: relative;
      overflow: hidden;
    }

    .message.loading::after {
      content: "";
      position: absolute;
      inset: 0;
      background: linear-gradient(90deg, transparent, rgba(255,255,255,0.5), transparent);
      animation: shimmer 1.4s infinite;
    }

    @keyframes shimmer {
      from { transform: translateX(-100%); }
      to { transform: translateX(100%); }
    }

    .composer {
      padding: 16px 18px 18px;
      border-top: 1px solid var(--line);
      background: rgba(255,255,255,0.5);
    }

    textarea, input[type="text"], input[type="number"] {
      width: 100%;
      border: 1px solid var(--line);
      border-radius: 14px;
      padding: 12px 14px;
      font: inherit;
      background: rgba(255,255,255,0.88);
      color: var(--text);
    }

    textarea { min-height: 108px; resize: vertical; }

    .row {
      display: flex;
      gap: 10px;
      align-items: center;
    }

    .row > * { flex: 1; }

    button {
      border: none;
      border-radius: 14px;
      background: var(--accent);
      color: white;
      padding: 11px 14px;
      font: inherit;
      font-weight: 700;
      cursor: pointer;
    }

    button:disabled {
      opacity: 0.55;
      cursor: not-allowed;
    }

    button.secondary {
      background: rgba(255,255,255,0.78);
      color: var(--text);
      border: 1px solid var(--line);
    }

    button.warn {
      background: #8a4f10;
    }

    .aside-scroll {
      padding: 14px;
      overflow: auto;
      display: flex;
      flex-direction: column;
      gap: 14px;
      min-height: 0;
    }

    .card {
      background: rgba(255,255,255,0.62);
      border: 1px solid var(--line);
      border-radius: 18px;
      padding: 14px;
    }

    .card h3 {
      margin: 0 0 10px;
      font-size: 14px;
    }

    .task-item {
      padding: 10px 0;
      border-top: 1px dashed var(--line);
    }

    .task-item:first-child { border-top: none; padding-top: 0; }
    .task-title { font-weight: 700; }
    .task-status { font-size: 12px; color: var(--muted); margin-top: 4px; }
    .task-summary, .mono {
      font-size: 13px;
      color: var(--muted);
      white-space: pre-wrap;
      word-break: break-word;
    }

    .empty {
      color: var(--muted);
      font-size: 13px;
    }

    .toggle {
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 10px;
      margin: 10px 0;
      font-size: 13px;
    }

    .status-bar {
      padding: 0 18px 10px;
      color: var(--warn);
      font-size: 13px;
      min-height: 18px;
    }

    @media (max-width: 1180px) {
      .layout {
        grid-template-columns: 1fr;
      }
      .sidebar, .aside, .main {
        min-height: 360px;
      }
    }
  </style>
